steps.apply:
count1 = 2;   /* for joining P2 and P3 before P5 */
count2 = 2;   /* for joining P5 and P6 before P7 */

/* Process P1 */
P1;           /* execute P1 */
FORK L1;     /* spawn P3 branch concurrently */
FORK L2;     /* spawn P4 branch concurrently */
              /* main thread continues as P2 */
/* P2 branch */
P2;
JOIN count1; /* decrement count1; if > 0 this thread ends */
              /* when count1 = 0: both P2 and P3 done, continue as P5 */
P5;
JOIN count2; /* decrement count2; if > 0 this thread ends */
              /* when count2 = 0: both P5 and P6 done, continue as P7 */
P7;
STOP;

L1: /* P3 branch */
  P3;
  JOIN count1; /* join with P2 */
  /* this thread ends if it is not the last */

L2: /* P4 branch */
  P4;
  P6;
  JOIN count2; /* join with P5 */
  /* this thread ends if it is not the last */
